/********************************
 * Créer un nouveau compte client.
 * Retourne 0 en cas de succès, 1 si le client existe déjà et 2 si la base de données est pleine.
 */
int *
creer_compte_1_svc(client *cl, struct svc_req *rqstp)
{
	static int  result;
	printf("Création de compte pour %s %s \n", cl->cl_prenom, cl->cl_nom);
	/* Vérifier si le client existe déjà */
	for(int i=0; i<nb_clients; i++)
	{
		if(strcmp(clients[i].cl_email, cl->cl_email) == 0)
		{
			printf("Le client existe déjà !\n");
			// échec : client existe déjà
			result = 1; 
			return &result;
		}
	}
	/* Ajouter le client à la "base de données" */
	if(nb_clients < MAX_CLIENTS) 
	{
		clients[nb_clients++] = *cl;
		printf("Compte créé avec succès !\n");
		result = 0; // succès
		return &result;
	} else {
		printf("La base de données est pleine !\n");
		result = 2; // échec : base de données pleine
		return &result;
	}
}

