/**
 * Afficher la repartition des usages dun client pour un mois 
 * retourne un struct usage_result avec les montants par poste
 */
usage_result *
afficher_usages_1_svc(requete_mois *argp, struct svc_req *rqstp)
{
	static usage_result  result;
	int res = 1;
    memset(&result, 0, sizeof(usage_result));
    printf("les usages pour %s du mois %d/%d \n", argp->email, argp->mois, argp->annee);
    
	for(int i=0; i<nb_clients; i++)
    {
        if(strcmp(clients[i].cl_email, argp->email) == 0)
        {
                strcpy(result.us_email, argp->email);
                /* la consommation totale du mois */
                float total = 0;
                for(int d=0; d<31; d++)
                {
                        total += consommations[i][argp->mois-1][d].cons_euros;
                }
                /* reparttition par poste de consommation */
                result.us_chauffage = total * 0.40; /* 40% chauffage */
                result.us_cuisson = total * 0.15; /* 15% cuisson */
                result.us_eclairage = total * 0.10; /* 10% éclairage */
                result.us_electromenager = total * 0.25; /* 25% électroménager */
                result.us_autres = total * 0.10; /* 10% autres */
                printf("Usages : chauffage=%.2f, cuisson=%.2f, eclairage=%.2f, electromenager=%.2f, autres=%.2f euros \n",
                        result.us_chauffage, result.us_cuisson, result.us_eclairage,
                        result.us_electromenager, result.us_autres);
                res = 0;
                return &result;
        }
     }
     if(res == 1) {
           printf("Le client nexiste pas .\n");
     }

	return &result;
}


